<?php namespace App\Repositories\Attendance;use App\Repositories\BaseRepository;use App\Models\Attendance\Attendance;use Illuminate\Database\Eloquent\Collection;use Illuminate\Pagination\LengthAwarePaginator;class AttendanceRepository extends BaseRepository{    public function __construct(Attendance $model)    {        $this->model = $model;        parent::__construct($model);    }    public function getByDate(string $date): Collection    {        return $this->query()->whereDate('date', $date)->get();    }    public function getByStudent(int $studentId): Collection    {        return $this->findByField('student_id', $studentId);    }    public function getByClass(int $classId): Collection    {        return $this->findByField('class_id', $classId);    }    public function getByDateRange(string $startDate, string $endDate): Collection    {        return $this->query()->whereBetween('date', [$startDate, $endDate])->get();    }    public function bulkMarkAttendance(array $records): bool    {        $data = [];        foreach ($records as $record) {            $data[] = [                'student_id' => $record['student_id'],                'class_id' => $record['class_id'],                'section_id' => $record['section_id'] ?? null,                'date' => $record['date'],                'status' => $record['status'],                'attendance_type' => $record['attendance_type'] ?? 'daily',                'time_in' => $record['time_in'] ?? null,                'time_out' => $record['time_out'] ?? null,                'reason' => $record['reason'] ?? null,                'marked_by' => $record['marked_by'] ?? null,                'created_at' => now(),                'updated_at' => now(),            ];        }        return $this->bulkInsert($data);    }    public function getAttendanceReport(int $classId, ?int $sectionId, string $startDate, string $endDate): Collection    {        $query = $this->query()->where('class_id', $classId)->whereBetween('date', [$startDate, $endDate]);        if ($sectionId) {            $query->where('section_id', $sectionId);        }        return $query->get();    }    public function getStudentAttendanceSummary(int $studentId, string $startDate, string $endDate): array    {        $records = $this->query()->where('student_id', $studentId)->whereBetween('date', [$startDate, $endDate])->get();        $total = $records->count();        $present = $records->where('status', 'present')->count();        $absent = $records->where('status', 'absent')->count();        $late = $records->where('status', 'late')->count();        $halfDay = $records->where('status', 'half_day')->count();        return [            'total' => $total,            'present' => $present,            'absent' => $absent,            'late' => $late,            'half_day' => $halfDay,            'percentage' => $total > 0 ? round(($present / $total) * 100, 2) : 0,        ];    }    public function getTodayByClass(int $classId, ?int $sectionId = null): Collection    {        $query = $this->query()->where('class_id', $classId)->whereDate('date', now());        if ($sectionId) {            $query->where('section_id', $sectionId);        }        return $query->get();    }    public function getAbsentStudentsByDate(string $date): Collection    {        return $this->query()->whereDate('date', $date)->where('status', 'absent')->get();    }    public function upsertAttendance(array $record): Attendance    {        $existing = $this->query()->where('student_id', $record['student_id'])->whereDate('date', $record['date'])->first();        if ($existing) {            $this->update($existing->id, $record);            return $existing->fresh();        }        return $this->create($record);    }}